                        : activeStep === step
                          ? 'border-primary text-primary bg-primary/10'
                          : 'border-outline-variant/60 text-on-surface-variant hover:border-primary/60 hover:text-primary'
                    }`}
                  >
                    Step {step}
                  </button>
                ))}
              </div>
            </div>

            <StepCard
