@import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@300;400;500;600;700;800&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:wght@100..700&display=swap');
@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --font-sans: 'Plus Jakarta Sans', ui-sans-serif, system-ui, sans-serif;
  --color-surface: #f9f9ff;
  --color-surface-container: #e9edff;
  --color-surface-container-low: #f1f3ff;
  --color-surface-container-high: #e1e8fd;
  --color-surface-container-highest: #dce2f7;
  --color-surface-container-lowest: #ffffff;
  --color-primary: #0058be;
  --color-primary-container: #2170e4;
  --color-on-primary: #ffffff;
  --color-on-surface: #141b2b;
  --color-on-surface-variant: #424754;
  --color-outline: #c8d1ef;
  --color-outline-variant: #e4e8f8;
}

@layer base {
  html {
    scroll-behavior: smooth;
  }

  body {
    @apply bg-surface text-on-surface antialiased;
    font-feature-settings: 'ss01', 'ss02', 'cv01', 'cv02';
  }
}

.glass-nav {
  @apply backdrop-blur-xl border-b border-white/10;
  background-color: rgba(255, 255, 255, 0.8);
}

.premium-shadow {
  box-shadow: 0 20px 40px rgba(20, 27, 43, 0.05);
}

.ambient-lift {
  box-shadow: 0 20px 40px rgba(0, 88, 190, 0.05);
}

.neon-purple-glow {
  box-shadow: 0 0 20px rgba(168, 85, 247, 0.2), 0 0 40px rgba(168, 85, 247, 0.1);
}

.hide-scrollbar::-webkit-scrollbar {
  display: none;
}

.hide-scrollbar {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

.material-symbols-outlined {
  font-variation-settings: 'FILL' 0, 'wght' 400, 'GRAD' 0, 'opsz' 24;
}

